export const epochs: EpochConfig[] = [{"id":"first-journey","name":"Our First Journey","subtitle":"Athens → Santa Cruz → Monterey Bay","description":"A beginner's journey across the world. Networking is the highway system that gets you from Athens to Santa Cruz. The internet is the surf you ride when you arrive. Security hygiene is what keeps you safe on a fishing trip in Monterey Bay.","emoji":"🌊","color":"emerald","unlocked":true},{"id":"ancient","name":"Foundations","subtitle":"Core Security Principles","description":"Master the concepts every security professional builds on — from the CIA Triad to SQL injection, from phishing to zero-day exploits. Each challenge is set inside one of the great sites of the ancient world.","emoji":"🛡️","color":"amber","unlocked":true},{"id":"cisco-core","name":"Cisco: Core CVEs","subtitle":"NSA Exploits & Network Fundamentals","description":"Foundational Cisco network infrastructure attacks — IOS buffer overflows, SNMP exploits, and the NSA's weaponized Cisco tools leaked by Shadow Brokers and Vault 7.","emoji":"🌐","color":"blue","unlocked":true},{"id":"cisco-enterprise","name":"Cisco: Enterprise Attack","subtitle":"Nation-State Campaigns & Advanced CVEs","description":"Advanced exploitation across Cisco's enterprise portfolio — ASA, NX-OS, SD-WAN, Expressway, and the ArcaneDoor and Velvet Ant nation-state campaigns.","emoji":"🏢","color":"indigo","unlocked":true},{"id":"cisco-secops","name":"Cisco: Security Operations","subtitle":"CyberOps, Threat Hunting & Zero-Day Defense","description":"Cisco security platform operations and CyberOps Associate skills — Firepower, Umbrella, ISE, SecureX/XDR, SOC triage, threat hunting, and the IOS XE CVSS 10.0 zero-day.","emoji":"🔒","color":"violet","unlocked":true},{"id":"cisco-advanced","name":"Cisco: Advanced Defense","subtitle":"Firepower, XDR, DevNet, Silicon One & Quantum-Safe","description":"Next-generation Cisco security — Firepower NGIPS/FTD evasion and CVEs, Cisco XDR threat hunting, DevNet API and NETCONF/YANG security, Silicon One P4 pipeline integrity, and post-quantum IKEv2 with ML-KEM-768.","emoji":"⚡","color":"cyan","unlocked":true},{"id":"tech-audit-1","name":"Tech Audit: Foundations","subtitle":"ISACA Audit Methodology","description":"Master IT audit methodology using ISACA standards — COBIT, CISA, CRISC, and ITGC. Each stage simulates a real audit engagement at a major institution, from risk assessment to audit reporting.","emoji":"🔍","color":"purple","unlocked":true},{"id":"tech-audit-2","name":"Tech Audit: Technical","subtitle":"API Security, Secrets & Cloud Guardrails","description":"Hands-on technical audit testing — enumerate and exploit API misconfigurations, hunt for exposed secrets, audit IAM policies, test cloud guardrails, scan IaC templates, and validate container security controls.","emoji":"🛠️","color":"violet","unlocked":true},{"id":"tech-audit-3","name":"Agentic Continuous Monitoring","subtitle":"Automated Audit with Claude Tools","description":"Automate the full audit lifecycle using Claude's tool use API and MCP servers — agentic API enumeration, AI-powered secrets scanning, automated compliance report generation, and multi-agent audit pipeline design.","emoji":"🤖","color":"indigo","unlocked":true},{"id":"tech-audit-4","name":"Continuous Monitoring 2.0","subtitle":"AI-Powered Detection and Response","description":"Master next-generation continuous monitoring: ML-enhanced SIEM, UEBA, NDR, CSPM, SOAR automation, deception technology, Zero Trust telemetry, XDR, and compliance monitoring — the full stack of modern SOC operations.","emoji":"📡","color":"rose","unlocked":true},{"id":"mitre","name":"MITRE ATT&CK","subtitle":"Adversary Tactics & Techniques","description":"Walk through all 12 ATT&CK tactic phases as the attacker — from reconnaissance to impact. Understand how real APTs operate and how defenders detect each phase using the industry-standard adversary framework.","emoji":"⚔️","color":"red","unlocked":true},{"id":"mitre-atlas","name":"MITRE ATLAS","subtitle":"AI/ML Adversarial Threat Landscape","description":"Attack AI and ML systems using MITRE ATLAS tactics — reconnaissance against ML pipelines, adversarial input crafting, model poisoning, model theft via extraction, and full AI kill chain synthesis using real incident case studies.","emoji":"🧠","color":"fuchsia","unlocked":true},{"id":"owasp-llm","name":"OWASP LLM Top 10","subtitle":"AI Application Security","description":"Master the OWASP LLM Top 10 (2025) — the definitive catalog of vulnerabilities in large language model applications. From prompt injection to unbounded consumption, learn to attack and defend AI systems through hands-on CTF missions based on real-world LLM exploits.","emoji":"🦙","color":"orange","unlocked":true},{"id":"sec-foundations","name":"Security Foundations","subtitle":"Governance, Controls, Physical Security & Resilience","description":"Hands-on hacking teaches you how attacks work — but certification exams (Security+, Network+, CySA+, ISC² CC, and the ISACA governance certs) also test the foundational, conceptual half of security: the taxonomy of controls and frameworks, physical security and deception, change management, cryptographic solutions, identity and access management, data protection, resilience and disaster recovery, and security awareness. This epoch rounds out the curriculum with the concepts every security professional must know — the exam-objective bedrock beneath the exploits.","emoji":"🏛️","color":"slate","unlocked":true},{"id":"ai-ml-foundations","name":"AI & Machine Learning Foundations","subtitle":"From data and training to generative AI and MLOps","description":"The platform's AI content focuses on attacking and defending AI systems — but the AI/ML certifications (CompTIA AI+, AWS AI Practitioner, Google Cloud ML Engineer) also test how machine learning actually works: the types of learning, data preparation, model training and evaluation, generative AI and foundation models, the MLOps lifecycle, and the cloud platforms (SageMaker, Bedrock, Vertex AI) that run it all. This epoch builds that engineering foundation — the exam-objective bedrock beneath the AI security content.","emoji":"🤖","color":"purple","unlocked":true},{"id":"quantum-1","name":"Quantum Foundations","subtitle":"Qubits, Algorithms & Cryptographic Threats","description":"Understand how quantum computing threatens the cryptographic foundations of the modern internet — from RSA to AES. Explore superposition, entanglement, Shor's Algorithm, and the Harvest Now, Decrypt Later threat that is already underway.","emoji":"⚛️","color":"cyan","unlocked":true},{"id":"quantum-2","name":"Post-Quantum Cryptography","subtitle":"NIST PQC Standards & Implementation","description":"Master the post-quantum cryptography standards that will replace RSA and ECC — CRYSTALS-Kyber (ML-KEM), CRYSTALS-Dilithium (ML-DSA), FALCON (FN-DSA), and SPHINCS+ (SLH-DSA). Learn the mathematics behind lattice-based cryptography and implement PQC in real systems.","emoji":"🔐","color":"teal","unlocked":true},{"id":"quantum-3","name":"Quantum Security","subtitle":"QKD, Agility & Enterprise Migration","description":"Deploy quantum-safe infrastructure end-to-end — BB84 QKD protocols, quantum key distribution networks, cryptographic agility frameworks, quantum-safe VPNs and PKI, liboqs integration, FIPS 140-3 compliance, and full enterprise PQC migration planning.","emoji":"🛰️","color":"sky","unlocked":true},{"id":"quantum-4","name":"Quantum Risk Management","subtitle":"CBOM, Migration Programs & Governance","description":"Build cryptographic inventories, design PQC migration programs, assess sector-specific quantum risk, and brief the board — using NIST, CISA, and NSA CNSA 2.0 frameworks.","emoji":"⚠️","color":"emerald","unlocked":true},{"id":"quantum-5","name":"Quantum-Safe Migration Engineering","subtitle":"PQC in Production — Discovery to Cutover","description":"The hands-on engineering of post-quantum migration: building a Cryptographic Bill of Materials, designing crypto-agility, deploying hybrid key exchange in TLS/SSH/VPN, migrating PKI and HSMs, integrating PQC libraries, sizing performance, validating against FIPS 140-3, and running a staged cutover with rollback — through to constrained and embedded devices.","emoji":"🛠️","color":"blue","unlocked":true},{"id":"quantum-intro","name":"Quantum for Curious Minds","subtitle":"Quantum Physics & Computing from Scratch","description":"A gentle, jargon-light on-ramp to the quantum world — no physics degree required. Build real intuition for superposition, measurement, wave-particle duality, interference, and entanglement, then meet the qubit, quantum gates, and what quantum computers can (and can't) actually do — each idea anchored to the experiment that proved it.","emoji":"🌌","color":"purple","unlocked":true},{"id":"quantum-deep","name":"Quantum, Deeper","subtitle":"Spin, Tunneling, Atoms & the Strange Rules of Reality","description":"The next step after the beginner quantum track: spin and the Stern-Gerlach experiment, quantum tunneling (the trick behind flash memory and the Sun), the Pauli principle that makes matter solid, atomic orbitals and the periodic table, photons and light-matter interaction, decoherence and the measurement problem, Bell's theorem and nonlocality, quantum error correction, a gentle peek at quantum field theory, and the interpretations we still argue about.","emoji":"🌀","color":"fuchsia","unlocked":true},{"id":"computing-foundations","name":"How Computers Really Work","subtitle":"From Electrons to Bits to Code","description":"The foundation everything else sits on, built from scratch: what electricity actually is, how circuits and transistors switch it, how switches become logic and binary, how logic does math and remembers, how a CPU runs a program, how your code becomes voltages — and why all of it is, underneath, a physical thing an attacker can probe.","emoji":"⚡","color":"orange","unlocked":true},{"id":"silicon-fab","name":"Silicon: Sand to Superchips","subtitle":"How the Newest GPU & Quantum Chips Are Made","description":"The most complex manufacturing on Earth, told from the beginning: how ordinary quartz sand becomes 99.9999999%-pure silicon, how a wafer is grown and sliced, how light prints circuits finer than a virus, what EUV machines do, how doping and etching sculpt billions of transistors, how FinFET and gate-all-around devices work, how a giant AI GPU is stitched together from chiplets and stacked memory — and how the radically different quantum processors at the frontier are fabricated.","emoji":"💠","color":"sky","unlocked":true},{"id":"space-race","name":"Race Through Space","subtitle":"Hacking the Systems Behind the New Space Race","description":"The deep-tech, hands-on side of today's space race. As SpaceX, NASA, China, and a wave of newcomers fill orbit with satellites, every spacecraft is a flying computer reachable over radio — and a target. Learn the real architecture (orbits, link budgets, the four segments), then break it: replay the Viasat wiper, spoof GPS, hijack a telecommand link, decode raw CCSDS telemetry, poison a ground-station supply chain, and inject on a MIL-STD-1553 spacecraft bus — finishing with counterspace warfare and how the constellation era gets secured.","emoji":"🚀","color":"violet","unlocked":true},{"id":"vehicle-sec","name":"Wired & Autonomous","subtitle":"Hacking Electric, Connected & Self-Driving Vehicles","description":"A modern car is a network of 100+ computers on wheels — and an electric, connected, increasingly self-driving one is a rolling attack surface. Build the foundations (the in-vehicle network, ECUs, the four domains) then go deep: inject on the CAN bus, brute a UDS seed-key, relay a keyless fob, hijack an EV charging session, own the telematics unit for remote control (the Jeep Cherokee hack), spoof ADAS sensors into phantom braking, and secure the fleet from firmware to cloud API.","emoji":"🚗","color":"lime","unlocked":true},{"id":"robot-sec","name":"Robotics","subtitle":"Hacking Robots, Drones & Autonomous Machines","description":"Robots are computers that can touch the physical world — so hacking one means moving an arm, flying a drone, or fooling a machine's eyes. Build the foundations (sense-plan-act, sensors, actuators, controllers) then go deep: inject on an unauthenticated ROS/DDS graph, command an exposed industrial robot arm, hijack a drone over MAVLink, seize a teleoperation channel, fool perception with an adversarial patch, and backdoor robot firmware — finishing with humanoid robots, functional safety, and how autonomous systems get secured.","emoji":"🤖","color":"orange","unlocked":true},{"id":"ot-sec","name":"Operational Technology","subtitle":"Securing ICS, SCADA & the Physical World","description":"Operational Technology (OT) is the computing that runs the physical world — the power grid, water plants, refineries, factories, and pipelines. These industrial control systems (ICS) were built for decades of uptime and physical safety, not for the internet, and yet they are increasingly connected. Start with the foundations (the IT/OT divide, the Purdue model, PLCs) then go hands-on: force a Modbus coil, hijack an HMI, spoof a DNP3 command, pivot from IT to OT through the engineering workstation, and learn the lessons of Stuxnet, TRITON, and the Ukraine grid attacks — finishing with how real plants are segmented, monitored, and recovered.","emoji":"🏭","color":"amber","unlocked":true},{"id":"vehicle-sec-2","name":"Wired & Autonomous II","subtitle":"The Software-Defined Vehicle, Deeper","description":"The first vehicle epoch covered the CAN bus, the OBD-II port, and remote car hacking. This one goes where cars are actually heading: zonal architectures on Automotive Ethernet, vehicle-to-everything (V2X) radio, phone-as-a-key and relay attacks, EV charging PKI (ISO 15118 Plug & Charge), the autonomous sensor-fusion stack, connected-car fleet APIs, and the regulations (UNECE R155/R156, ISO/SAE 21434) now forcing automakers to build security in. Hands-on CTFs throughout — spoof a SOME/IP service, forge a V2X safety message, relay a key fob, hijack a charging session, and take over a fleet API.","emoji":"🚗","color":"lime","unlocked":true},{"id":"robot-sec-2","name":"Robotics II","subtitle":"Fleets, Farms, Swarms & Learned Behavior","description":"The first robotics epoch covered the anatomy of a robot, ROS/DDS, drones, teleoperation, and perception. This one scales out and goes specialized: the ROS 2 / SROS2 security model, exploiting a DDS domain, commandeering a warehouse AMR fleet (VDA5050), hijacking an autonomous tractor, swarm-robotics trust, cloud-robotics backends, legged and humanoid platforms, navigation/GPS spoofing, poisoning a robot's learned policy, and securing robot fleets at scale. Hands-on CTFs throughout.","emoji":"🦾","color":"orange","unlocked":true},{"id":"space-race-2","name":"Race Through Space II","subtitle":"Links, Ground Segments & Constellations","description":"The first space epoch introduced satellites, ground stations, and why space is hard to secure. This one goes operational and adversarial: hijacking a satellite's command uplink (TT&C), eavesdropping unencrypted downlinks, spoofing GNSS time, jamming and anti-jam, breaching the ground segment (the Viasat lesson), CubeSats and mega-constellations, pivoting across inter-satellite links, space situational awareness and ASAT, and securing space systems with SPARTA and resilience. Hands-on CTFs throughout.","emoji":"🚀","color":"violet","unlocked":true},{"id":"threat-frameworks","name":"Threat Frameworks","subtitle":"Thinking Like an Analyst — Kill Chain to ATT&CK","description":"Tools find alerts; frameworks turn alerts into understanding. This epoch teaches the mental models analysts use to make sense of an adversary: the Cyber Kill Chain, the Diamond Model, MITRE ATT&CK and the ATT&CK Navigator, the Pyramid of Pain, MITRE D3FEND, and STIX/TAXII for sharing — all tied together by the threat-intelligence lifecycle and threat-informed defense. Hands-on analyst exercises (map an intrusion to the kill chain, pivot the Diamond, tag behavior with ATT&CK technique IDs, climb the Pyramid of Pain, map a defense in D3FEND, and author a STIX indicator) alongside the concepts.","emoji":"🎯","color":"rose","unlocked":true},{"id":"flag-football-1","name":"Flag Football: Foundations","subtitle":"First snap to the basics of offense, defense & agility","description":"Flag football — the fastest-growing team sport in America and an Olympic sport for LA 2028 — taught from the ground up. This first epoch builds your foundation: what the game is, the field and game flow, positions and rules, pulling flags (the tackle of flag football), throwing and catching, running routes, and the basics of offense, defense (man vs zone), agility, and conditioning.","emoji":"🏈","color":"emerald","unlocked":true},{"id":"flag-football-2","name":"Flag Football: Advanced Play","subtitle":"High-school-level schemes, coverages & game IQ","description":"The deep, high-school-level half of flag football. Build on the foundations to master formations and pre-snap motion, the quarterback's reads and progressions, receiver craft, route concepts (smash, flood, mesh), defensive coverages (Cover 0–3, match, disguise), the 7-yard pass rush, run-game misdirection, defensive strategy and adjustments, athletic development, and the game IQ that wins close games — all the way to the college and Olympic pathway.","emoji":"🏈","color":"teal","unlocked":true},{"id":"flag-football-3","name":"Flag Football: Playbook & Competition","subtitle":"Building & calling plays, special situations, coaching & winning","description":"Where the knowledge becomes a winning program. This epoch is applied flag football: building and calling a playbook, scoring in the red zone and no-run zones, beating the blitz with hot routes, trick plays, designed defensive pressure, scouting and film study, practice design and team culture, season conditioning, the mental game, and managing a tournament all the way to a championship.","emoji":"🏈","color":"green","unlocked":true},{"id":"physics-of-hacking","name":"The Physics of Hacking","subtitle":"Side Channels, Faults & Hardware Attacks","description":"Where electricity and physics become attacks. Computation is physical, so it leaks (power, electromagnetic, timing, sound, light), it lingers (memory remanence), and it can be disturbed (Rowhammer, fault injection) — and the supply chain that builds the hardware can be subverted. Each stage is a real attack class and its real defense.","emoji":"🧲","color":"pink","unlocked":true},{"id":"emerging-tech","name":"Emerging Tech & Deep Learning Risk","subtitle":"Foundation Models, Agentic AI & Governance","description":"Security risks of emerging AI technologies — deep learning attack surfaces, foundation model supply chains, federated learning vulnerabilities, synthetic media fraud, AI-augmented threats, edge AI exploitation, governance frameworks, and agentic AI risk.","emoji":"🤖","color":"violet","unlocked":true},{"id":"umbrella","name":"Cisco Umbrella","subtitle":"DNS Security & Threat Intelligence","description":"Master DNS-layer security with Cisco Umbrella — the world's most deployed cloud security platform. From DNS tunneling to DGA detection, from lookalike domains to DoH evasion, each mission puts you inside a real Umbrella SOC investigation.","emoji":"☂️","color":"indigo","unlocked":true},{"id":"tapestry","name":"The Woven World","subtitle":"Tapestry — History, Tradition & Modern Practice","description":"Travel through 3,000 years of tapestry: from Egyptian tombs and Andean mummy wrappings to the great Flemish workshops, Persian courts, Navajo hogans, and the modern artist's studio. Learn to weave, mix colors on the loom, and read the language of thread.","emoji":"🧵","color":"yellow","unlocked":true},{"id":"nails","name":"Nail Arts","subtitle":"The Professional Nail Studio","description":"Master professional nail technique from the ground up — prep, the no-water rule, even polish application, troubleshooting lifting and chipping, and the business of running your own nail operation. Real skills, real results.","emoji":"💅","color":"pink","unlocked":true},{"id":"hair-color","name":"Hair Coloring","subtitle":"From Chemistry to Art","description":"Understand how hair absorbs color, master the level system, learn developer and lift, choose between permanent and semi-permanent formulas, apply safely, bleach and tone, correct color mistakes, and build a hair coloring business.","emoji":"🎨","color":"rose","unlocked":true},{"id":"hair-styling","name":"Hair Styling","subtitle":"Tools, Technique & Transformation","description":"Master the full toolkit of professional hair styling — from understanding hair types and heat science to braiding, curls, and client-ready updos. Then take your craft into business.","emoji":"✂️","color":"violet","unlocked":true},{"id":"driving-1","name":"Road to Your License","subtitle":"California DMV Test Prep","description":"Master California driving laws and pass the DMV written knowledge test. Learn the rules of the road, road signs, speed limits, right-of-way laws, DUI statutes, and what examiners look for on the behind-the-wheel test — everything you need to earn your California driver's license.","emoji":"🚗","color":"yellow","unlocked":true},{"id":"driving-2","name":"First Miles","subtitle":"Beginning Driver Skills","description":"Build real confidence behind the wheel — from cockpit checks and smooth starts to highway merging and night driving. Every great driver started exactly where you are now.","emoji":"🚙","color":"lime","unlocked":true},{"id":"driving-3","name":"Rules of the Road","subtitle":"Wisdom Every Driver Needs","description":"Passing the test is just the beginning. Becoming a genuinely safe, thoughtful driver means mastering the skills no written exam covers — distraction awareness, defensive technique, handling emergencies, and treating every trip as a responsibility to yourself and everyone around you.","emoji":"🛣️","color":"orange","unlocked":true},{"id":"baseball-1","name":"Play Ball!","subtitle":"Little League Fundamentals","description":"Learn America's game from the ground up — the diamond, the rules, how to hit, pitch, field, and run the bases with confidence. But the game is more than mechanics: it's about hustle, teamwork, and respecting the sport. Whether you're brand new or looking to sharpen your skills, these fundamentals will take you from first throw to full team player.","emoji":"⚾","color":"red","unlocked":true},{"id":"baseball-2","name":"The Art of Hitting","subtitle":"Mastering the Batter's Box","description":"Hitting a round ball with a round bat is the hardest skill in professional sports — and the most rewarding when you get it right. This epoch dives deep into every facet of the craft: stance, pitch recognition, swing mechanics, plate discipline, power, contact adjustments, and the legendary Dodger hitters who mastered it all. From Jackie Robinson's bunts to Shohei Ohtani's leg kick, you'll learn to think like the best hitters in the world — and train like them too.","emoji":"🏏","color":"blue","unlocked":true},{"id":"baseball-3","name":"Advanced Mechanics","subtitle":"The Science of the Swing","description":"You have mastered the fundamentals — now you go deeper. Advanced hitting is where biomechanics meet psychology, where data meets feel, and where the margins between a good hitter and a great one are measured in milliseconds and degrees. This epoch explores hip-shoulder separation, barrel management, load timing, two-strike mastery, situational hitting, pitch sequencing, adverse conditions, slump psychology, and the cutting-edge video technology the Dodgers and elite hitters use to refine every swing. From Camelback Ranch in spring training to Oracle Park on a foggy October night, you will think like the best hitters in the world.","emoji":"⚡","color":"violet","unlocked":true},{"id":"baseball-4","name":"Elite Mastery","subtitle":"Hitting Like a Pro","description":"You have learned the mechanics, studied the pitches, and built a practice routine. Now comes the hardest part: playing like a professional. This epoch is for hitters who want to think at the highest level — using Statcast analytics, pre-at-bat scouting, mental preparation, clutch execution, platoon strategy, cutting-edge technology, and a lifetime of development philosophy. From Dodger Stadium to Cooperstown, from the on-deck circle to the broadcast booth, this is hitting at its most complete.","emoji":"🏆","color":"amber","unlocked":true},{"id":"baseball-5","name":"The Art of Pitching","subtitle":"Mechanics & Fundamentals","description":"Pitching is the most technically demanding skill in baseball — a symphony of biomechanics, mental fortitude, and strategic intelligence executed in under two seconds on every delivery. This epoch breaks down the complete craft: the rubber and stance, grip science, windup and stretch mechanics, arm action, release point command, holding runners, velocity, pitch counts, fielding, and the mound mindset. From Clayton Kershaw's legendary delivery to the pitch count rules protecting young arms, you will learn to think and throw like the best in the game.","emoji":"⚾","color":"green","unlocked":true},{"id":"baseball-6","name":"Pitch Arsenal","subtitle":"Grips, Movement & Sequencing","description":"Every pitcher tells a story with their arsenal — a sequence of speeds, shapes, and locations designed to keep hitters off-balance and guessing wrong. This epoch goes deep on every pitch type from the four-seam fastball to the splitter, covering grip mechanics, spin science, movement physics, and the Rapsodo revolution that transformed how Dodger pitching coaches develop arms. From Clayton Kershaw's El Diablo curveball to Mariano Rivera's career-ending cutter to Hideo Nomo's devastating forkball, you will learn to grip, throw, and sequence every weapon in a complete pitcher's arsenal — and build your own repertoire the right way.","emoji":"🎯","color":"red","unlocked":true},{"id":"baseball-7","name":"Pitching Strategy","subtitle":"The Chess Match on the Mound","description":"Pitching is the deepest intellectual game in baseball — a chess match played at 95 miles per hour, where every pitch is a calculated move and every batter is a puzzle to be solved. This epoch dives into the strategic mind of a pitcher: reading batters before a pitch is thrown, manipulating counts, sequencing pitches across an entire lineup, and managing a start from the first inning through the third time through the order. From Sandy Koufax's elegant simplicity to Clayton Kershaw's career-long evolution, the greatest Dodger pitchers teach every principle covered here. Learn to think from the mound — and you will never watch a game the same way again.","emoji":"🧠","color":"indigo","unlocked":true},{"id":"baseball-8","name":"Catcher","subtitle":"The Field General Behind the Plate","description":"The catcher is the only player who faces the entire field — and the only one involved in every single pitch. This complete position course builds the catcher from the ground up: the stances, receiving and framing, blocking balls in the dirt, the pop-time footwork to throw out runners, fielding bunts and pop-ups, plays at the plate, the backups and coverages for every situation, calling a game, and building the durable lower body the job demands. From Little League to Mike Piazza — the Dodgers' Hall of Famer and the greatest-hitting catcher in history — you will learn to run the defense, protect the plate, and become the leader every pitching staff trusts.","emoji":"🧤","color":"red","unlocked":true},{"id":"baseball-9","name":"First Base","subtitle":"The Anchor of the Infield","description":"First base is the busiest receiving position on the diamond — nearly every infield out passes through the first baseman's glove. This complete position course builds the first baseman from the ground up: footwork at the bag, stretching and scooping throws out of the dirt, holding runners, fielding the 3-hole and starting double plays, charging bunts, serving as a cutoff, and the backups and coverages for every situation. From Little League to Freddie Freeman — the Dodgers' Gold Glove cornerstone and World Series MVP — you will learn to anchor the infield and turn your teammates' throws — good and bad — into outs.","emoji":"🧤","color":"orange","unlocked":true},{"id":"baseball-10","name":"Second Base","subtitle":"The Pivot and the Keystone Partner","description":"Second base is the keystone of the middle infield — the pivot man on the double play and the shortstop's partner up the middle. This complete position course builds the second baseman from the ground up: positioning and range to both sides, fielding and footwork, turning the double play from the second-base side, feeding the shortstop, covering the bag on steals and bunts, serving as a relay and cutoff man, and the situational reads that make a keystone defender. From Little League to Jackie Robinson — the Brooklyn Dodgers' Hall of Famer who redefined the position with athleticism, intelligence, and daring — you will learn to turn two, guard the middle, and anchor the defense beside your shortstop.","emoji":"🔃","color":"blue","unlocked":true},{"id":"baseball-11","name":"Third Base","subtitle":"The Hot Corner","description":"Third base is the hot corner — the position closest to right-handed pull hitters, where balls arrive harder and faster than anywhere on the diamond and reactions decide everything. This complete position course builds the third baseman from the ground up: the reaction-ready stance, quick and soft hands on smashes, the long throw across the diamond, charging slow rollers and bare-handing bunts, guarding the line, serving as a cutoff, and the situational reads the corner demands. From Little League to Adrián Beltré — a Dodgers product who became a Hall of Famer and one of the greatest defensive third basemen ever — you will learn to guard the hot corner with fearless hands and a cannon arm.","emoji":"🔥","color":"red","unlocked":true},{"id":"baseball-12","name":"Shortstop","subtitle":"The Captain of the Infield","description":"Shortstop is the most demanding position on the infield — the most ground to cover, the hardest throws to make, and the leadership to captain the entire defense. This complete position course builds the shortstop from the ground up: range to both sides, the deep-hole backhand and jump throw, turning the double play, charging slow rollers, covering the bag, leading cutoffs and relays, positioning the defense, and the all-around athleticism the position requires. From Little League to Ozzie Smith's thirteen Gold Gloves, you will learn to cover the middle, make the impossible throw, and become the captain every infield is built around.","emoji":"🪄","color":"indigo","unlocked":true},{"id":"baseball-13","name":"Left Field","subtitle":"Reading the Ball off the Bat","description":"Left field is where most balls are hit — the corner that demands reading the slice off right-handed pull hitters, playing the line and the wall, and throwing to third with accuracy. This complete position course builds the left fielder from the ground up: reading the ball off the bat, the first step and routes, catching fly balls and line drives, playing caroms off the wall, the crow-hop throw, hitting cutoffs, backing up bases, and the situational reads of the corner. From Little League to Zack Wheat — the Brooklyn Dodgers' graceful Hall of Fame left fielder and franchise hits leader — you will learn to track down every ball, play the wall, and keep runners from taking the extra base.","emoji":"🧤","color":"green","unlocked":true},{"id":"baseball-14","name":"Center Field","subtitle":"The Captain of the Outfield","description":"Center field is the outfield's most demanding position — the most ground to cover, the deepest alignment, priority on every catchable ball, and the leadership to captain the outfield. This complete position course builds the center fielder from the ground up: reading the ball and the jump, route running across the gaps, catching and robbing home runs at the wall, the long throw, priority and calling off the corners, backing up second base and the middle, and the situational reads that lead the outfield. From Little League to Ken Griffey Jr.'s effortless grace, you will learn to run down everything, rob homers, and captain the outfield.","emoji":"🎯","color":"blue","unlocked":true},{"id":"baseball-15","name":"Right Field","subtitle":"The Cannon","description":"Right field is the strong-arm corner — the position with the longest throw to third base, where a cannon arm controls the running game. This complete position course builds the right fielder from the ground up: reading the ball off the bat, catching fly balls and line drives, the long throw to third and home, playing the line and the sun, backing up first base, hitting cutoffs, and the situational reads of the corner. From Little League to Mookie Betts — the Dodgers' multiple-Gold-Glove right fielder and World Series champion — you will learn to run down everything, unleash the cannon, and stop runners from taking the extra base.","emoji":"🚀","color":"orange","unlocked":true},{"id":"debate-1","name":"Foundations of Debate","subtitle":"From Your First Round to a Confident Speaker","description":"Debate is the disciplined art of disagreement — the skill of taking a side, defending it with reasons and evidence, and answering the strongest objections honestly. This first journey starts at zero: what a resolution is, how to build a single clean argument, how to take notes on a fast round, how speeches and cross-examination fit together, and how to win a ballot without ever being rude. Master these foundations and every format that follows becomes learnable.","emoji":"🎙️","color":"sky","unlocked":true},{"id":"debate-2","name":"Argumentation & Logic","subtitle":"The Reasoning Engine Beneath Every Argument","description":"Foundations gave you the shape of an argument; this epoch gives you the engine. You'll learn the Toulmin model that maps any real argument, the difference between deductive certainty and inductive strength, how to tell causation from mere correlation, and how to name and dismantle the formal and informal fallacies that sink weak cases. By the end you'll spot a broken inference the instant you hear it — and never build one yourself.","emoji":"🧠","color":"cyan","unlocked":true},{"id":"debate-3","name":"The Formats","subtitle":"Every Major Style of Competitive Debate","description":"There is no single 'debate' — there is a family of formats, each with its own speech order, judging style, and culture. Policy rewards research depth; Lincoln-Douglas rewards philosophy; Public Forum rewards persuasion before ordinary people; Parliamentary and British Parliamentary reward thinking on your feet; Congress simulates a legislature; Mock Trial puts you in a courtroom. This epoch is a guided tour of all of them, so you can read any round, speak in any chamber, and choose the format that fits you.","emoji":"🏛️","color":"teal","unlocked":true},{"id":"debate-4","name":"Research & Case Construction","subtitle":"Turning a Resolution Into a Case That Wins","description":"Knowing how to argue is not the same as having something to argue. This epoch is the workshop: how to analyze a resolution, research and organize evidence, build a constructive case with framework and contentions, structure a policy plan or Public Forum case, weigh impacts so the judge knows why you win, pre-write blocks against predictable attacks, and prepare against your own case. By the end you can take any resolution and build a complete, defensible case from scratch.","emoji":"🏗️","color":"emerald","unlocked":true},{"id":"debate-5","name":"Clash","subtitle":"Refutation, Rebuttal, and Winning the Exchange","description":"Cases are built in advance; rounds are won in the clash. This epoch is the combat manual: how to read the flow as a battlefield, refute at every layer, turn an opponent's argument into your own offense, run cross-examination like a strategist, extend and frontline your arguments through the round, collapse onto your winners, concede with purpose, crystallize the final speech, and hunt the dropped argument. These are the skills that decide who actually wins.","emoji":"⚔️","color":"amber","unlocked":true},{"id":"debate-6","name":"Rhetoric, Delivery & Persuasion","subtitle":"How You Say It Is Half of What You Say","description":"A flawless case persuades no one if it's delivered poorly. This epoch is the art of delivery: the three appeals of ethos, pathos, and logos; vocal and physical command; the speed-versus-persuasion question; word economy; narrative and framing; the classical rhetorical devices; adapting to any audience; managing nerves; and finding your own authentic, persuasive voice. Master these and your reasoning finally reaches the judge with its full force.","emoji":"🎭","color":"rose","unlocked":true},{"id":"debate-7","name":"Competitive & Professional Mastery","subtitle":"The Circuit, the Credentials, and the Career","description":"The final ascent: judge paradigms and adaptation at the highest level, the advanced procedural and critical arguments (theory, topicality, kritiks, counterplans, disadvantages), tournament strategy across a season, and — most of all — the real credentials and recognition debate offers: the NSDA degree ladder and Academic All American, Toastmasters Pathways and the DTM, collegiate and international honors (NFA, AFA, WUDC, World Schools), and the Tournament of Champions. It closes with the careers and lifelong value that make every hour of debate an investment.","emoji":"🏆","color":"indigo","unlocked":true},{"id":"debate-8","name":"The Psychology of Debate","subtitle":"How Minds Actually Reason, Judge, and Change","description":"Every round happens inside human minds — yours, your opponent's, and the judge's — and those minds run on cognitive machinery that decades of psychology have mapped. This epoch is the science beneath persuasion: the cognitive biases that distort reasoning, the principles of influence, how judges actually decide, the role of emotion, cognitive load, reading people, why minds resist good arguments, psychological inoculation, the psychology of credibility, and the debater's own mental game. Master it and you persuade not by intuition but by understanding how persuasion truly works.","emoji":"🧠","color":"purple","unlocked":true},{"id":"paris-july","name":"Paris in July","subtitle":"City of Light — your practical guide to summer in Paris","description":"Walk Paris like a local: where to go, how to get there, what to book ahead, and the stories that make each place worth it.","emoji":"🗼","color":"blue","unlocked":true},{"id":"milan-july","name":"Milan in July","subtitle":"Design capital, ancient canals, and aperitivo hour at 6:30pm","description":"Navigate Milan like a local: skip-the-line tactics for the Last Supper, the aperitivo circuit, day trips to Lake Como and Pavia, and what actually stays open in August.","emoji":"🍕","color":"red","unlocked":true},{"id":"french-basics","name":"French Basics","subtitle":"Essential French for visiting Paris","description":"Learn the French phrases that matter: cafés, restaurants, markets, metro, museums, and how to survive a conversation with a real Parisian.","emoji":"🇫🇷","color":"blue","unlocked":true},{"id":"italian-basics","name":"Italian Basics","subtitle":"Essential Italian for visiting Milan","description":"Learn the Italian phrases that matter: bar culture, trattorie, fashion shopping, the tram network, and how to survive aperitivo like a local.","emoji":"🇮🇹","color":"green","unlocked":true}];
